import { bar_position, bar_styles, racing_bar_position } from './bar-encode';
import { bar_subdivider_position } from './bar-subdivider-encode';
import { boxplot_whisker_position, boxplot_whisker_styles } from '../boxplot/boxplot-whisker-encode';
import { bullet_levelmarker_position, bullet_levelmarker_styles } from '../bullet/bullet-levelmarker-encode';
import { MarksRegistry } from '../plot/MarksRegistry';

export function bar_encode_collectors() {
    bar_position.call(this);
    bar_subdivider_position.call(this);
    boxplot_whisker_position.call(this);
    bullet_levelmarker_position.call(this);

    // let racing = this.chart.racing;
    // if (racing) {
        racing_bar_position.call(this);
    // }

    bar_styles.call(this);
    let morphing = this.chart.systemConf.chart.plot.morph.enabled && this.chart.oldSeriesInfo;
    if (morphing) {
        MarksRegistry.get('bar.morph').call(this);
    }
    
    // boxplot_whisker_styles.call(this);
    bullet_levelmarker_styles.call(this);
}
